  def _clean(obj: str) -> str:
          """Strip surrounding quotes and whitespace, replace underscores with spaces."""
          obj = obj.strip()
          if (obj.startswith('"') and obj.endswith('"')) or (obj.startswith("'") and obj.endswith("...
              obj = obj[1:-1].strip()
          return obj.replace("_", " ")

      for t in triples:
          obj_clean = _clean(t.object)
          tmpl = templates.get(t.predicate)
          if tmpl:
              # Render full clause then strip the subject part to keep only the predicate phrase
              full_clause = tmpl.format(s=t.subject, o=obj_clean)
              # Remove leading subject if present
              if full_clause.startswith(t.subject):
                  phrase = full_clause[len(t.subject):].lstrip()
              else:
                  phrase = full_clause
          else:
              # Fallback generic phrasing without repeating the subject
              phrase = f"{t.predicate} {obj_clean}"
